parameters.query:
INSERT INTO julia_lead_memory (
  phone,

  contact_id,
  conversation_id,
  account_id,
  inbox_id,

  lead_name,
  company_name,

  lead_source_type,
  source_label,

  lead_status,
  fit_score,

  nome_responsavel,
  origem_clientes,
  principal_gargalo,
  interesse_em_crescer,
  tem_agencia,

  responsavel_confirmado,
  responsavel_terceiro,
  contato_responsavel,
  origem_clientes_identificada,
  gargalo_identificado,
  pedido_preco,
  pedido_detalhes,
  handoff_realizado,
  ultima_pergunta_feita,

  motivo_score,
  resumo_conversa,
  proximo_passo,
  observacoes,

  last_message,
  last_response,
  last_message_id,

  tags_adicionar,
  tags_remover,
  raw_result,

  first_seen_at,
  last_seen_at,
  updated_at
)
VALUES (
  '{{ String($('RESPONDER').item.json.lead.phone || "").replace(/\\/g, "\\\\").replace(/'/g, "''") }}',

  {{ $('RESPONDER').item.json.chatwoot.contact_id || $('RESPONDER').item.json.lead.id || 'NULL' }},
  {{ $('RESPONDER').item.json.chatwoot.conversation_id || 'NULL' }},
  {{ $('RESPONDER').item.json.chatwoot.account_id || 'NULL' }},
  {{ $('RESPONDER').item.json.chatwoot.inbox_id || 'NULL' }},

  '{{ String($('RESPONDER').item.json.lead.name || "").replace(/\\/g, "\\\\").replace(/'/g, "''") }}',
  '{{ String($('RESPONDER').item.json.parsed_output?.empresa || $('RESPONDER').item.json.lead.empresa_detectada || $('RESPONDER').item.json.lead.company_name || $('RESPONDER').item.json.crm_update?.empresa || "").replace(/\\/g, "\\\\").replace(/'/g, "''") }}',

  '{{ String($('RESPONDER').item.json.parsed_output?.lead_source_type || $('RESPONDER').item.json.crm_update?.lead_source_type || $('RESPONDER').item.json.lead.source_type || $('RESPONDER').item.json.lead.source || "").replace(/\\/g, "\\\\").replace(/'/g, "''") }}',
  '{{ String($('RESPONDER').item.json.lead.source_label || $('RESPONDER').item.json.conversation?.source_label || "").replace(/\\/g, "\\\\").replace(/'/g, "''") }}',

  '{{ (() => {
    const j = $('RESPONDER').item.json;
    const p = j.parsed_output || j.agent?.result || {};
    const finalHandoff = j.should_handoff === true || p.handoff_humano === true;

    let status = String(p.status || j.crm_update?.lead_status || j.lead?.lead_status || "").trim();

    if (status === "QUALIFICADO_HUMANO" && !finalHandoff) {
      status = "EM_ANDAMENTO";
    }

    return status.replace(/\\/g, "\\\\").replace(/'/g, "''");
  })() }}',

  {{ (() => {
    const j = $('RESPONDER').item.json;
    const p = j.parsed_output || j.agent?.result || {};
    const value = p.score_de_0_a_100 ?? j.crm_update?.fit_score ?? j.lead?.fit_score;
    return Number.isFinite(Number(value)) ? Number(value) : 'NULL';
  })() }},

  '{{ String($('RESPONDER').item.json.parsed_output?.nome_responsavel || $('RESPONDER').item.json.crm_update?.nome_responsavel || $('RESPONDER').item.json.lead.responsible_name || "").replace(/\\/g, "\\\\").replace(/'/g, "''") }}',
  '{{ String($('RESPONDER').item.json.parsed_output?.origem_clientes || $('RESPONDER').item.json.crm_update?.origem_clientes || $('RESPONDER').item.json.lead.origem_clientes || "").replace(/\\/g, "\\\\").replace(/'/g, "''") }}',
  '{{ String($('RESPONDER').item.json.parsed_output?.principal_gargalo || $('RESPONDER').item.json.crm_update?.principal_gargalo || $('RESPONDER').item.json.lead.principal_gargalo || "").replace(/\\/g, "\\\\").replace(/'/g, "''") }}',
  '{{ String($('RESPONDER').item.json.parsed_output?.interesse_em_crescer || $('RESPONDER').item.json.crm_update?.interesse_em_crescer || $('RESPONDER').item.json.lead.interesse_em_crescer || "").replace(/\\/g, "\\\\").replace(/'/g, "''") }}',

  {{ (() => {
    const j = $('RESPONDER').item.json;
    const p = j.parsed_output || j.agent?.result || {};
    const value = p.tem_agencia ?? j.crm_update?.tem_agencia ?? j.lead?.tem_agencia;

    if (value === null || value === undefined || value === "") return 'NULL';

    const text = String(value).trim().toLowerCase();

    if (value === true || value === 1 || ["true", "sim", "yes", "1"].includes(text)) return 1;
    if (value === false || value === 0 || ["false", "não", "nao", "no", "0"].includes(text)) return 0;

    return 'NULL';
  })() }},

  {{ (() => {
    const j = $('RESPONDER').item.json;
    const p = j.parsed_output || j.agent?.result || {};

    const name =
      p.nome_responsavel ||
      j.crm_update?.nome_responsavel ||
      j.lead?.responsible_name ||
      "";

    const value = p.responsavel_confirmado;
    const text = String(value).trim().toLowerCase();

    return value === true || value === 1 || ["true", "sim", "yes", "1"].includes(text) || Boolean(String(name).trim()) ? 1 : 0;
  })() }},

  {{ (() => {
    const j = $('RESPONDER').item.json;
    const p = j.parsed_output || j.agent?.result || {};

    const value = p.responsavel_terceiro;
    const text = String(value).trim().toLowerCase();

    return value === true || value === 1 || ["true", "sim", "yes", "1"].includes(text) ? 1 : 0;
  })() }},

  '{{ String($('RESPONDER').item.json.parsed_output?.contato_responsavel || $('RESPONDER').item.json.crm_update?.telefone_responsavel || $('RESPONDER').item.json.lead.responsible_phone || "").replace(/\\/g, "\\\\").replace(/'/g, "''") }}',

  {{ (() => {
    const j = $('RESPONDER').item.json;
    const p = j.parsed_output || j.agent?.result || {};

    const origem =
      p.origem_clientes ||
      j.crm_update?.origem_clientes ||
      j.lead?.origem_clientes ||
      "";

    const value = p.origem_clientes_identificada;
    const text = String(value).trim().toLowerCase();

    return value === true || value === 1 || ["true", "sim", "yes", "1"].includes(text) || Boolean(String(origem).trim()) ? 1 : 0;
  })() }},

  {{ (() => {
    const j = $('RESPONDER').item.json;
    const p = j.parsed_output || j.agent?.result || {};

    const gargalo =
      p.principal_gargalo ||
      j.crm_update?.principal_gargalo ||
      j.lead?.principal_gargalo ||
      "";

    const value = p.gargalo_identificado;
    const text = String(value).trim().toLowerCase();

    return value === true || value === 1 || ["true", "sim", "yes", "1"].includes(text) || Boolean(String(gargalo).trim()) ? 1 : 0;
  })() }},

  {{ (() => {
    const j = $('RESPONDER').item.json;
    const p = j.parsed_output || j.agent?.result || {};
    const status = String(p.status || j.crm_update?.lead_status || j.lead?.lead_status || "").trim();

    const value = p.pedido_preco;
    const text = String(value).trim().toLowerCase();

    return value === true || value === 1 || ["true", "sim", "yes", "1"].includes(text) || status === "PEDIU_PRECO" ? 1 : 0;
  })() }},

  {{ (() => {
    const j = $('RESPONDER').item.json;
    const p = j.parsed_output || j.agent?.result || {};
    const status = String(p.status || j.crm_update?.lead_status || j.lead?.lead_status || "").trim();

    const value = p.pedido_detalhes;
    const text = String(value).trim().toLowerCase();

    return (
      value === true ||
      value === 1 ||
      ["true", "sim", "yes", "1"].includes(text) ||
      ["PEDIU_DIAGNOSTICO", "PEDIU_PROPOSTA", "PEDIU_REUNIAO"].includes(status)
    ) ? 1 : 0;
  })() }},

  {{ (() => {
    const j = $('RESPONDER').item.json;
    const p = j.parsed_output || j.agent?.result || {};

    return j.should_handoff === true || p.handoff_humano === true ? 1 : 0;
  })() }},

  '{{ (() => {
    const j = $('RESPONDER').item.json;
    const response = String(j.message_to_send || j.resposta_final || "");
    const questions = response.match(/[^.!?\n]*\?/g) || [];
    const lastQuestion = questions.length ? questions[questions.length - 1].trim() : "";

    return lastQuestion.slice(0, 1000).replace(/\\/g, "\\\\").replace(/'/g, "''");
  })() }}',

  '{{ String($('RESPONDER').item.json.parsed_output?.motivo_score || $('RESPONDER').item.json.crm_update?.motivo_score || "").replace(/\\/g, "\\\\").replace(/'/g, "''") }}',
  '{{ String($('RESPONDER').item.json.parsed_output?.resumo_conversa || $('RESPONDER').item.json.crm_update?.resumo_conversa || "").replace(/\\/g, "\\\\").replace(/'/g, "''") }}',
  '{{ String($('RESPONDER').item.json.parsed_output?.proximo_passo || $('RESPONDER').item.json.crm_update?.proximo_passo || "").replace(/\\/g, "\\\\").replace(/'/g, "''") }}',
  '{{ String($('RESPONDER').item.json.parsed_output?.observacoes || $('RESPONDER').item.json.crm_update?.observacoes || "").replace(/\\/g, "\\\\").replace(/'/g, "''") }}',

  '{{ String($('RESPONDER').item.json.message?.content_for_ai || $('RESPONDER').item.json.message?.content || "").replace(/\\/g, "\\\\").replace(/'/g, "''") }}',
  '{{ String($('RESPONDER').item.json.message_to_send || $('RESPONDER').item.json.resposta_final || "").replace(/\\/g, "\\\\").replace(/'/g, "''") }}',
  {{ $('RESPONDER').item.json.chatwoot.message_id || 'NULL' }},

  '{{ JSON.stringify($('RESPONDER').item.json.labels_update?.add || []).replace(/\\/g, "\\\\").replace(/'/g, "''") }}',
  '{{ JSON.stringify($('RESPONDER').item.json.labels_update?.remove || []).replace(/\\/g, "\\\\").replace(/'/g, "''") }}',

  '{{ (() => {
    const j = $('RESPONDER').item.json;
    const p = j.parsed_output || j.agent?.result || {};
    const finalHandoff = j.should_handoff === true || p.handoff_humano === true;

    const raw = {
      status: p.status || "",
      resposta: j.message_to_send || j.resposta_final || "",
      deve_responder: p.deve_responder ?? j.should_reply ?? true,

      handoff_humano: finalHandoff,
      motivo_handoff: p.motivo_handoff || "",

      score_de_0_a_100: p.score_de_0_a_100 || 0,
      motivo_score: p.motivo_score || "",

      resumo_conversa: p.resumo_conversa || "",
      proximo_passo: p.proximo_passo || "",

      lead_source_type: p.lead_source_type || "",

      nome_responsavel: p.nome_responsavel || "",
      empresa: p.empresa || "",
      origem_clientes: p.origem_clientes || "",
      principal_gargalo: p.principal_gargalo || "",
      interesse_em_crescer: p.interesse_em_crescer || "",
      tem_agencia: p.tem_agencia ?? null,

      responsavel_confirmado: p.responsavel_confirmado ?? null,
      responsavel_terceiro: p.responsavel_terceiro ?? null,
      contato_responsavel: p.contato_responsavel || "",

      origem_clientes_identificada: p.origem_clientes_identificada ?? null,
      gargalo_identificado: p.gargalo_identificado ?? null,
      pedido_preco: p.pedido_preco ?? null,
      pedido_detalhes: p.pedido_detalhes ?? null,

      faz_anuncios: p.faz_anuncios ?? null,
      tem_funcionarios: p.tem_funcionarios ?? null,
      capacidade_status: p.capacidade_status || "",
      capacidade_observacao: p.capacidade_observacao || "",

      observacoes: p.observacoes || ""
    };

    return JSON.stringify(raw).replace(/\\/g, "\\\\").replace(/'/g, "''");
  })() }}',

  NOW(),
  NOW(),
  NOW()
)
ON DUPLICATE KEY UPDATE
  contact_id = VALUES(contact_id),
  conversation_id = VALUES(conversation_id),
  account_id = VALUES(account_id),
  inbox_id = VALUES(inbox_id),

  lead_name = COALESCE(NULLIF(VALUES(lead_name), ''), lead_name),
  company_name = COALESCE(NULLIF(VALUES(company_name), ''), company_name),

  lead_source_type = COALESCE(NULLIF(VALUES(lead_source_type), ''), lead_source_type),
  source_label = COALESCE(NULLIF(VALUES(source_label), ''), source_label),

  lead_status = COALESCE(NULLIF(VALUES(lead_status), ''), lead_status),
  fit_score = COALESCE(VALUES(fit_score), fit_score),

  nome_responsavel = COALESCE(NULLIF(VALUES(nome_responsavel), ''), nome_responsavel),
  origem_clientes = COALESCE(NULLIF(VALUES(origem_clientes), ''), origem_clientes),
  principal_gargalo = COALESCE(NULLIF(VALUES(principal_gargalo), ''), principal_gargalo),
  interesse_em_crescer = COALESCE(NULLIF(VALUES(interesse_em_crescer), ''), interesse_em_crescer),
  tem_agencia = COALESCE(VALUES(tem_agencia), tem_agencia),

  responsavel_confirmado = GREATEST(COALESCE(responsavel_confirmado, 0), COALESCE(VALUES(responsavel_confirmado), 0)),
  responsavel_terceiro = VALUES(responsavel_terceiro),
  contato_responsavel = COALESCE(NULLIF(VALUES(contato_responsavel), ''), contato_responsavel),

  origem_clientes_identificada = GREATEST(COALESCE(origem_clientes_identificada, 0), COALESCE(VALUES(origem_clientes_identificada), 0)),
  gargalo_identificado = GREATEST(COALESCE(gargalo_identificado, 0), COALESCE(VALUES(gargalo_identificado), 0)),
  pedido_preco = GREATEST(COALESCE(pedido_preco, 0), COALESCE(VALUES(pedido_preco), 0)),
  pedido_detalhes = GREATEST(COALESCE(pedido_detalhes, 0), COALESCE(VALUES(pedido_detalhes), 0)),

  handoff_realizado = VALUES(handoff_realizado),
  ultima_pergunta_feita = COALESCE(NULLIF(VALUES(ultima_pergunta_feita), ''), ultima_pergunta_feita),

  motivo_score = COALESCE(NULLIF(VALUES(motivo_score), ''), motivo_score),
  resumo_conversa = COALESCE(NULLIF(VALUES(resumo_conversa), ''), resumo_conversa),
  proximo_passo = COALESCE(NULLIF(VALUES(proximo_passo), ''), proximo_passo),
  observacoes = COALESCE(NULLIF(VALUES(observacoes), ''), observacoes),

  last_message = VALUES(last_message),
  last_response = VALUES(last_response),
  last_message_id = VALUES(last_message_id),

  tags_adicionar = VALUES(tags_adicionar),
  tags_remover = VALUES(tags_remover),
  raw_result = VALUES(raw_result),

  last_seen_at = NOW(),
  updated_at = NOW();

