const NODE_VERSION = "v6_clean_rerank_light";

function clean(value, preserveNewLines = false) {
  let text = "";

  if (value === undefined || value === null) {
    text = "";
  } else if (typeof value === "object") {
    try {
      text = JSON.stringify(value);
    } catch (error) {
      text = "";
    }
  } else {
    text = String(value);
  }

  text = text
    .replace(/\[object Object\]/gi, "")
    .replace(/[\u200B-\u200D\u2060\uFEFF]/g, " ")
    .replace(/\uFFFD/g, " ")
    .replace(/\r\n/g, "\n")
    .replace(/\r/g, "\n");

  if (preserveNewLines) {
    return text
      .split("\n")
      .map(line => line.replace(/[ \t]+/g, " ").trim())
      .filter(Boolean)
      .join("\n")
      .trim();
  }

  return text.replace(/\s+/g, " ").trim();
}

function asObject(value) {
  return value && typeof value === "object" && !Array.isArray(value) ? value : {};
}

function firstFilled(...values) {
  for (const value of values) {
    const text = clean(value, true);
    if (text) return text;
  }
  return "";
}

function normalize(value) {
  return clean(value)
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "");
}

function numberOrNull(value) {
  const n = Number(value);
  return Number.isFinite(n) ? n : null;
}

function parseIntentList(value) {
  if (Array.isArray(value)) {
    return [...new Set(value.map(item => clean(item)).filter(Boolean))];
  }

  if (typeof value === "string") {
    const text = clean(value);
    if (!text) return [];

    if (text.startsWith("[") && text.endsWith("]")) {
      try {
        const parsed = JSON.parse(text);
        if (Array.isArray(parsed)) {
          return [...new Set(parsed.map(item => clean(item)).filter(Boolean))];
        }
      } catch (error) {}
    }

    return [...new Set(text.split(",").map(item => clean(item)).filter(Boolean))];
  }

  return [];
}

function getOriginal() {
  try {
    return $("Monta Query Playbook Julia").item.json || {};
  } catch (error) {
    return $json || {};
  }
}

function getLeadSourceType(original) {
  return firstFilled(
    original.agent?.lead_source_type,
    original.agent?.playbook_mode,
    original.lead?.source_type,
    original.lead?.source,
    original.conversation?.lead_source_type,
    original.conversation?.playbook_mode,
    "indefinido"
  );
}

function normalizeDoc(doc) {
  const metadata = asObject(doc.metadata);

  const content = firstFilled(
    doc.content,
    doc.pageContent,
    doc.text,
    doc.document,
    doc.conteudo
  );

  const arquivo = firstFilled(
    metadata.arquivo_origem,
    metadata.source,
    doc.source,
    doc.file,
    doc.filename,
    "origem não informada"
  );

  const tipo = firstFilled(
    metadata.tipo_documento,
    metadata.tipo,
    doc.tipo_documento,
    "playbook"
  );

  const modo = firstFilled(
    metadata.modo,
    doc.modo,
    "global"
  );

  const tema = firstFilled(
    metadata.tema,
    metadata.assunto,
    metadata.categoria,
    doc.tema,
    "sem tema"
  );

  const prioridade = numberOrNull(
    firstFilled(metadata.prioridade_regra, doc.prioridade_regra)
  );

  const ativoRaw = metadata.ativo ?? doc.ativo ?? true;
  const ativo = ativoRaw === true || String(ativoRaw).toLowerCase() === "true";

  const similarity = numberOrNull(doc.similarity);

  const docIntents = [
    ...parseIntentList(metadata.intents),
    ...parseIntentList(metadata.intent),
    ...parseIntentList(doc.intents),
    ...parseIntentList(doc.intent)
  ];

  return {
    ...doc,
    content,
    metadata,

    arquivo,
    tipo,
    modo,
    tema,
    prioridade_regra: prioridade,
    ativo,
    similarity,
    doc_intents: [...new Set(docIntents)],

    tipo_norm: normalize(tipo),
    modo_norm: normalize(modo),
  };
}

function scoreDoc(doc, leadSourceType) {
  let score = 0;
  const explain = [];

  const similarity = typeof doc.similarity === "number" ? doc.similarity : 0;
  score += similarity;
  explain.push(`similarity:${similarity.toFixed(3)}`);

  const prioridade = typeof doc.prioridade_regra === "number"
    ? doc.prioridade_regra / 100
    : 0.5;

  score += prioridade;
  explain.push(`prioridade:${prioridade.toFixed(2)}`);

  if (doc.modo_norm === leadSourceType) {
    score += 1.2;
    explain.push("modo_exato:+1.2");
  }

  if (doc.modo_norm === "global") {
    score += 0.6;
    explain.push("global:+0.6");
  }

  if (doc.tipo_norm === "nao_fazer") {
    score += 0.4;
    explain.push("nao_fazer_base:+0.4");
  }

  return { score, explain };
}

const original = getOriginal();
const leadSourceType = getLeadSourceType(original);

const docsRaw = $input.all().map(item => item.json);

const normalizedDocs = docsRaw
  .map(normalizeDoc)
  .filter(doc => doc.content && doc.ativo);

const scoredDocs = normalizedDocs.map(doc => {
  const scoreResult = scoreDoc(doc, leadSourceType);

  return {
    ...doc,
    rank_score: scoreResult.score,
    rank_explain: scoreResult.explain,
  };
});

const docsRanked = scoredDocs
  .sort((a, b) => b.rank_score - a.rank_score)
  .slice(0, 5);

const knowledgeContext = docsRanked
  .map((doc, index) => {
    const similarity = typeof doc.similarity === "number"
      ? ` | similaridade: ${doc.similarity.toFixed(3)}`
      : "";

    const rank = typeof doc.rank_score === "number"
      ? ` | rank: ${doc.rank_score.toFixed(3)}`
      : "";

    const intentsDoc = doc.doc_intents.length
      ? ` | intents=${doc.doc_intents.join(",")}`
      : "";

    return [
      `${index + 1}. [${doc.tipo} | modo=${doc.modo} | tema=${doc.tema} | ${doc.arquivo}${similarity}${rank}${intentsDoc}]`,
      doc.content
    ].join("\n");
  })
  .join("\n\n---\n\n");

return [
  {
    json: {
      ...original,

      agent: {
        ...(original.agent || {}),

        lead_source_type: leadSourceType,
        playbook_mode: leadSourceType,

        knowledge_context:
          knowledgeContext || "Nenhum playbook relevante foi encontrado.",

