const NODE_VERSION = "v6_clean_rerank_light";

function clean(value, preserveNewLines = false) {
  let text = "";

  if (value === undefined || value === null) {
    text = "";
  } else if (typeof value === "object") {
    try {
      text = JSON.stringify(value);
    } catch (error) {
      text = "";
    }
  } else {
    text = String(value);
  }

  text = text
    .replace(/\[object Object\]/gi, "")
    .replace(/[\u200B-\u200D\u2060\uFEFF]/g, " ")
    .replace(/\uFFFD/g, " ")
    .replace(/\r\n/g, "\n")
    .replace(/\r/g, "\n");

  if (preserveNewLines) {
    return text
      .split("\n")
      .map(line => line.replace(/[ \t]+/g, " ").trim())
      .filter(Boolean)
      .join("\n")
      .trim();
  }

  return text.replace(/\s+/g, " ").trim();
}

function asObject(value) {
  return value && typeof value === "object" && !Array.isArray(value) ? value : {};
}

function firstFilled(...values) {
  for (const value of values) {
    const text = clean(value, true);
    if (text) return text;
  }
  return "";
}

function normalize(value) {
  return clean(value)
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "");
}

function numberOrNull(value) {
  const n = Number(value);
  return Number.isFinite(n) ? n : null;
}

function parseIntentList(value) {
  if (Array.isArray(value)) {
    return [...new Set(value.map(item => clean(item)).filter(Boolean))];
  }

  if (typeof value === "string") {
    const text = clean(value);
    if (!text) return [];

    if (text.startsWith("[") && text.endsWith("]")) {
      try {
        const parsed = JSON.parse(text);
        if (Array.isArray(parsed)) {
          return [...new Set(parsed.map(item => clean(item)).filter(Boolean))];
        }
      } catch (error) {}
    }

    return [...new Set(text.split(",").map(item => clean(item)).filter(Boolean))];
  }

  return [];
}

