function normalizeDoc(doc) {
  const metadata = asObject(doc.metadata);

  const content = firstFilled(
    doc.content,
    doc.pageContent,
    doc.text,
    doc.document,
    doc.conteudo
  );

  const arquivo = firstFilled(
    metadata.arquivo_origem,
    metadata.source,
    doc.source,
    doc.file,
    doc.filename,
    "origem não informada"
  );

  const tipo = firstFilled(
    metadata.tipo_documento,
    metadata.tipo,
    doc.tipo_documento,
    "playbook"
  );

  const modo = firstFilled(
    metadata.modo,
    doc.modo,
    "global"
  );

  const tema = firstFilled(
    metadata.tema,
    metadata.assunto,
    metadata.categoria,
    doc.tema,
    "sem tema"
  );

  const prioridade = numberOrNull(
    firstFilled(metadata.prioridade_regra, doc.prioridade_regra)
  );

  const ativoRaw = metadata.ativo ?? doc.ativo ?? true;
  const ativo = ativoRaw === true || String(ativoRaw).toLowerCase() === "true";

  const similarity = numberOrNull(doc.similarity);

  const docIntents = [
    ...parseIntentList(metadata.intents),
    ...parseIntentList(metadata.intent),
    ...parseIntentList(doc.intents),
    ...parseIntentList(doc.intent)
  ];

  return {
    ...doc,
    content,
    metadata,

    arquivo,
    tipo,
    modo,
    tema,
    prioridade_regra: prioridade,
    ativo,
    similarity,
    doc_intents: [...new Set(docIntents)],

    tipo_norm: normalize(tipo),
    modo_norm: normalize(modo),
  };
}

function scoreDoc(doc, leadSourceType) {
  let score = 0;
  const explain = [];

  const similarity = typeof doc.similarity === "number" ? doc.similarity : 0;
  score += similarity;
  explain.push(`similarity:${similarity.toFixed(3)}`);

  const prioridade = typeof doc.prioridade_regra === "number"
    ? doc.prioridade_regra / 100
    : 0.5;

  score += prioridade;
  explain.push(`prioridade:${prioridade.toFixed(2)}`);

  if (doc.modo_norm === leadSourceType) {
    score += 1.2;
    explain.push("modo_exato:+1.2");
  }

  if (doc.modo_norm === "global") {
    score += 0.6;
    explain.push("global:+0.6");
  }

  if (doc.tipo_norm === "nao_fazer") {
    score += 0.4;
    explain.push("nao_fazer_base:+0.4");
  }

  return { score, explain };
}

